import{_ as t,o as e,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F11: 處分重大資產與資本配置 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F11_處分重大資產與資本配置_投資研究員.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F11_處分重大資產與資本配置_投資研究員.md"}'),n={name:"審計報告庫/財務審計/3135_凌航/20260430/F11_處分重大資產與資本配置_投資研究員.md"};function o(l,a,s,c,h,_){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="f11-處分重大資產與資本配置-投資研究員-審計報告" tabindex="-1">F11: 處分重大資產與資本配置 - 投資研究員 審計報告 <a class="header-anchor" href="#f11-處分重大資產與資本配置-投資研究員-審計報告" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在處分重大資產（如土地、專利、子公司）之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>凌航科技（3135）無重大資產處分，PP&amp;E處分淨額歸零。業外虧損9,426仟元主因匯率波動，非變賣資產。本業營利率5.18%，獲利質量<strong>純淨</strong>。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>凌航科技2023年PP&amp;E處分成本5,328仟元，已提列等額累計折舊，處分損益歸零；2022年同模式無損益。營業外淨支出9,426仟元主因淨外幣兌換損失（2022年為利益48,525仟元），純匯率波動。公司輕資產模式（PP&amp;E佔總資產0.3%、全數委外代工），幾乎無重大資產可供處分，業外純匯率因素。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="獲利含金量穿透-earnings-purity" tabindex="-1">獲利含金量穿透 (Earnings Purity) <a class="header-anchor" href="#獲利含金量穿透-earnings-purity" aria-label="Permalink to &quot;獲利含金量穿透 (Earnings Purity)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2023年稅前淨利63,548仟元中，營業利益80,968仟元佔比127.5%，營業外淨支出(9,426)仟元為拖累項。扣除匯率波動後，本業實質營利率為3.15%（80,968/2,571,855）。</li><li><strong>深度見解</strong>：業外項目對淨利的侵蝕幅度為-14.8%（(9,426)/63,548），主因是2022年匯率順風（48,525仟元利益）消失後的正常化回落。本業營利率從2022年的-7.82%改善至2023年的3.15%，顯示本業正在復甦，獲利純度無虞。</li></ul><h3 id="戰略意圖判別-strategic-intent" tabindex="-1">戰略意圖判別 (Strategic Intent) <a class="header-anchor" href="#戰略意圖判別-strategic-intent" aria-label="Permalink to &quot;戰略意圖判別 (Strategic Intent)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2023年籌資活動淨流入624,865仟元（短期借款新增560,102仟元、應付短期票券新增99,813仟元），營運活動淨流出(887,857)仟元，投資活動淨流出(15,546)仟元。</li><li><strong>深度見解</strong>：公司處於「擴張備貨」階段，大量舉債為因應2023年下半年記憶體市場回溫而增加存貨（存貨從2022年底成長至2023年底），屬於「戰略性舉債」而非「救急補坑」。2024年1月簽約以5.04億元購置華固中原置地大樓作為新總部，整合分散於6處的租賃辦公空間，屬長期資本配置。</li></ul><h3 id="資產結構變動-asset-efficiency" tabindex="-1">資產結構變動 (Asset Efficiency) <a class="header-anchor" href="#資產結構變動-asset-efficiency" aria-label="Permalink to &quot;資產結構變動 (Asset Efficiency)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2023年底負債總額975,560仟元，較2022年底273,443仟元增加256.77%。流動比率從2022年底的6.61降至2023年底的1.89（但仍大於1）。資產週轉率為2.21（2,571,855/1,164,000）。</li><li><strong>深度見解</strong>：負債暴增主因短期借款從195,900仟元暴增至750,476仟元，搭配2024年購置總部5.04億元的承諾，資本結構將進一步槓桿化。輕資產模式下，ROA為5.33%（50,138/940,800），尚可接受但需監控負債品質。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：2023年營運現金流從2022年的635,765仟元流入轉為(887,857)仟元流出，現金及約當現金從374,620仟元驟降至74,101仟元，降幅80.2%。公司靠舉債維持流動性，若2024年記憶體需求不如預期，高杠杆結構將面臨壓力。</li><li><strong>空頭風險二</strong>：2024年購置總部5.04億元，佔2023年淨利（50,138仟元）的100.6倍，將大幅增加長期負債與折舊壓力。以30年直線折舊估算，每年新增折舊約1,680仟元；若以20,000仟股計，每年侵蝕EPS約0.08元（稅後）。更關鍵的是，購屋需舉債支應，假設貸款利率1.5%、貸款成數70%，每年利息支出約2,646仟元，稅後淨影響約1,950仟元。綜合折舊+利息，年侵蝕EPS約0.18元，佔2023年EPS（估2.51元）的7.2%。若記憶體價格回落導致本業營收萎縮，固定折舊與利息將放大虧損幅度，ROE可能從當前水準下滑1.5-2個百分點。在記憶體價格下行週期中，公司缺乏足夠的現金緩衝應對固定成本攤提，財務韌性顯著下降。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (finance)</strong>：OK。2023年營業外收支淨額-17,420仟元（全年），業外收入及支出-9,426仟元（半年度），其他利益及損失-10,910仟元，淨外幣兌換損失-9,448仟元。</li><li><strong>FinMind (balance_sheet)</strong>：OK。2023年底負債總額975,560仟元，短期借款750,476仟元。</li><li><strong>FinMind (cash_flow)</strong>：OK。2023年營運活動淨現金流出-887,857仟元，籌資活動淨流入624,865仟元。</li><li><strong>年報PDF</strong>：OK。P.117處分資產明細、P.125營業外收支、P.130籌資活動、P.137重大承諾（華固建設購屋合約）。</li><li><strong>MOPS/新聞</strong>：OK。2024年1月19日公告購置總部5.04億元，無重大資產處分公告。</li><li><strong>關鍵核對碼</strong>：2023年PP&amp;E處分5,328仟元=累計折舊5,328仟元，淨額=0；營業外淨支出9,426仟元=淨外幣兌換損失9,448仟元。</li></ul>',18)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
